window.DEFAULT_GRAMMAR = [{"unit": "Unit 1", "title": "Measurements & describing technical data", "sections": [{"title": "Numbers, decimals, ranges", "rules": ["Decimals: use “point” (2.75 → two point seven five).", "Ranges: “from … to …”, “between … and …”.", "Approximations: about / around / roughly / approximately."], "examples": [{"en": "The duct is 250 mm wide and 2.75 m long.", "fr": "La gaine fait 250 mm de large et 2,75 m de long."}, {"en": "The supply temperature is between 17°C and 19°C during normal operation.", "fr": "La température de soufflage est comprise entre 17°C et 19°C en fonctionnement normal."}, {"en": "The pressure drop is roughly 80 Pa at 500 m³/h.", "fr": "La perte de charge est d’environ 80 Pa à 500 m³/h."}], "exercises": [{"type": "fill", "q": "Écris en anglais : “3,5 kW”.", "a": "three point five kW", "why": "Décimales → “point”."}, {"type": "fill", "q": "Complète : “The temperature is ____ 20°C (≈).”", "a": "about", "why": "about/around/roughly/approximately = valeur approximative."}, {"type": "mcq", "q": "Choisis la meilleure phrase pour un intervalle : 40–60 Pa.", "choices": ["It is 40 at 60 Pa.", "It is between 40 and 60 Pa.", "It is from 40 and 60 Pa.", "It is 40 to 60 Pa between."], "answer": 1, "why": "between … and … / from … to …"}]}, {"title": "Describing a graph / trend (engineering reports)", "rules": ["Increase/decrease: rise, increase, go up / fall, drop, decrease, go down.", "Intensity: slightly / gradually / sharply / significantly.", "Cause/consequence (bridge to Unit 5): due to / therefore."], "examples": [{"en": "The airflow rate increased gradually after the damper was opened.", "fr": "Le débit d’air a augmenté progressivement après l’ouverture du clapet."}, {"en": "The CO₂ level dropped sharply due to higher ventilation.", "fr": "Le taux de CO₂ a chuté fortement grâce à une ventilation plus élevée."}], "exercises": [{"type": "fill", "q": "Complète : “The pressure ____ (drop) after cleaning the filter.”", "a": "dropped", "why": "Past simple (action terminée)."}, {"type": "mcq", "q": "Quel adverbe signifie “fortement / brusquement” ?", "choices": ["slightly", "sharply", "slowly", "rarely"], "answer": 1, "why": "sharply = brusquement."}]}]}, {"unit": "Unit 2", "title": "Adverbs & frequency in technical routines", "sections": [{"title": "Adverbs of frequency (position)", "rules": ["Before main verb: We usually check…", "After BE: The system is always…", "Negative frequency: never, hardly ever, rarely."], "examples": [{"en": "We usually verify the sensors before the functional test.", "fr": "On vérifie généralement les capteurs avant le test fonctionnel."}, {"en": "The safety switch is always tested before handover.", "fr": "Le contact de sécurité est toujours testé avant la réception."}], "exercises": [{"type": "mcq", "q": "Choisis la phrase correcte :", "choices": ["We check always the pressure.", "We always check the pressure.", "We check the always pressure.", "Always we check the pressure."], "answer": 1, "why": "Adverbe avant verbe principal."}, {"type": "fill", "q": "Complète : “The pump is ____ (never) opened under pressure.”", "a": "never", "why": "Never se place avant le verbe principal."}]}, {"title": "Time markers & procedures", "rules": ["Sequence: first / then / after that / finally.", "Frequency phrases: once a day, twice a week, every month.", "Safety language: always / never + imperative (Always stop…, Never open…)."], "examples": [{"en": "First, isolate the circuit; then, verify the voltage; finally, lock the panel.", "fr": "D’abord, isole le circuit ; ensuite, vérifie la tension ; enfin, verrouille le tableau."}, {"en": "We inspect the filters once a month during the heating season.", "fr": "On inspecte les filtres une fois par mois pendant la saison de chauffe."}], "exercises": [{"type": "fill", "q": "Complète : “We clean the strainer ____ a month.”", "a": "once", "why": "once a month = une fois par mois."}, {"type": "mcq", "q": "Quel mot indique la dernière étape ?", "choices": ["then", "finally", "after", "because"], "answer": 1, "why": "finally = dernière étape."}]}]}, {"unit": "Unit 3", "title": "Comparatives, superlatives & correlations", "sections": [{"title": "Comparatives (than) + common patterns", "rules": ["Short adjective: quieter, smaller, bigger.", "Long adjective: more efficient, less reliable.", "Structure: X is … than Y."], "examples": [{"en": "This fan is quieter than the old one.", "fr": "Ce ventilateur est plus silencieux que l’ancien."}, {"en": "A variable-speed pump is more efficient than a fixed-speed pump.", "fr": "Une pompe à vitesse variable est plus efficace qu’une pompe à vitesse fixe."}], "exercises": [{"type": "fill", "q": "Complète : “This duct is ____ (small) than the other one.”", "a": "smaller", "why": "small → smaller."}, {"type": "fill", "q": "Complète : “This solution is ____ efficient than the alternative.”", "a": "more", "why": "more + efficient."}]}, {"title": "Superlatives + design choices", "rules": ["the + -est: the smallest, the highest.", "the most + adj: the most efficient.", "Use in selection: the best option / the worst case."], "examples": [{"en": "This is the smallest valve in the set.", "fr": "C’est la plus petite vanne du lot."}, {"en": "The most efficient configuration uses heat recovery.", "fr": "La configuration la plus efficace utilise la récupération de chaleur."}], "exercises": [{"type": "mcq", "q": "Choisis la phrase correcte :", "choices": ["the most small", "the smallest", "smallest the", "more smallest"], "answer": 1, "why": "Superlatif de small = the smallest."}]}, {"title": "Correlations (the more…, the less…)", "rules": ["Structure: The more X, the more Y / the less Y.", "Often used in building physics / HVAC control."], "examples": [{"en": "The more airflow we supply, the lower the CO₂ level becomes.", "fr": "Plus on souffle, plus le CO₂ baisse."}, {"en": "The higher the setpoint, the more energy the system consumes.", "fr": "Plus la consigne est haute, plus le système consomme."}], "exercises": [{"type": "fill", "q": "Complète : “The ____ (high) the setpoint, the more energy is used.”", "a": "higher", "why": "high → higher."}]}]}, {"unit": "Unit 4", "title": "Degree, approximation & technical nuance", "sections": [{"title": "Degree adverbs (slightly → extremely)", "rules": ["Slightly / a bit = faible variation.", "Significantly / considerably = variation importante.", "Extremely / highly = intensité forte (souvent avec dependent/likely)."], "examples": [{"en": "The filter is slightly clogged, so the pressure drop increased.", "fr": "Le filtre est légèrement encrassé, donc la perte de charge a augmenté."}, {"en": "The result is highly dependent on the measurement method.", "fr": "Le résultat dépend fortement de la méthode de mesure."}], "exercises": [{"type": "mcq", "q": "Quel mot veut dire “légèrement” ?", "choices": ["highly", "slightly", "extremely", "totally"], "answer": 1, "why": "slightly = légèrement."}]}, {"title": "Approximations in specs & reports", "rules": ["approximately / roughly / around / about = valeur approchée.", "nearly / almost = proche d’une limite."], "examples": [{"en": "The unit weighs approximately 120 kg.", "fr": "L’unité pèse environ 120 kg."}, {"en": "The room is nearly at setpoint after 10 minutes.", "fr": "La pièce est presque à la consigne après 10 minutes."}], "exercises": [{"type": "fill", "q": "Complète : “The airflow is ____ 900 m³/h.”", "a": "approximately", "why": "Valeur approchée."}]}]}, {"unit": "Unit 5", "title": "Linking words (logic) for reports & explanations", "sections": [{"title": "Cause → consequence", "rules": ["Cause: because / since / due to + noun.", "Consequence: therefore / thus / as a result.", "Report style: due to (plus formel que because)."], "examples": [{"en": "The test failed because the sensor was wired incorrectly.", "fr": "Le test a échoué car le capteur était mal câblé."}, {"en": "The coil was dirty; therefore, the supply temperature dropped.", "fr": "La batterie était sale ; donc la température de soufflage a baissé."}], "exercises": [{"type": "mcq", "q": "Complète : “The coil was dirty, ____ the airflow decreased.”", "choices": ["however", "therefore", "although", "whereas"], "answer": 1, "why": "therefore = conséquence."}, {"type": "fill", "q": "Complète : “The shutdown was ____ a faulty safety switch.”", "a": "due to", "why": "due to + nom."}]}, {"title": "Opposition & concession", "rules": ["however = “cependant” (souvent après ; ou en début).", "although/even though = concession (phrase).", "whereas/while = contraste (2 faits)."], "examples": [{"en": "The pump is efficient; however, it is too noisy for this zone.", "fr": "La pompe est efficace ; cependant elle est trop bruyante."}, {"en": "Although the fan is new, the vibration level is high.", "fr": "Bien que le ventilateur soit neuf, le niveau de vibration est élevé."}], "exercises": [{"type": "fill", "q": "Complète : “____ the unit is new, it still needs calibration.”", "a": "Although", "why": "Although + phrase."}]}]}, {"unit": "Unit 6", "title": "Tenses for describing operation vs commissioning", "sections": [{"title": "Present simple vs continuous", "rules": ["Present simple: facts/routines (The system operates…).", "Present continuous: action now (We are testing…).", "Right now / currently → continuous."], "examples": [{"en": "The controller regulates the supply temperature automatically.", "fr": "Le régulateur contrôle automatiquement la température."}, {"en": "We are calibrating the sensors right now.", "fr": "Nous calibrons les capteurs en ce moment."}], "exercises": [{"type": "mcq", "q": "Choisis le bon temps : “Right now we ____ the pressure drop.”", "choices": ["measure", "are measuring", "measured", "have measured"], "answer": 1, "why": "Right now → continuous."}]}, {"title": "Past simple for completed actions (site logs)", "rules": ["Yesterday/last week → past simple.", "Use for commissioning steps: tested, replaced, recorded."], "examples": [{"en": "Yesterday we replaced the belt and recorded the vibration level.", "fr": "Hier on a remplacé la courroie et relevé le niveau de vibration."}], "exercises": [{"type": "fill", "q": "Complète : “We ____ (test) the fire damper last Friday.”", "a": "tested", "why": "Past simple."}]}, {"title": "Present perfect (experience / recent results)", "rules": ["Use: has/have + past participle (We have checked…).", "Already/yet → perfect.", "Difference: past simple = date/when; present perfect = result now."], "examples": [{"en": "We have already completed the functional test.", "fr": "Nous avons déjà terminé le test fonctionnel."}, {"en": "Have you checked the setpoints yet?", "fr": "Tu as déjà vérifié les consignes ?"}], "exercises": [{"type": "fill", "q": "Complète : “We have ____ (already) calibrated the sensor.”", "a": "already", "why": "already se place souvent entre have et participe."}]}]}];
